     9â†’import { Prompt } from '../prompt';
    10â†’import { Agent, AgentCallParameters, AgentStreamParameters } from './agent';
    11â†’import { ToolLoopAgentOnStepFinishCallback } from './tool-loop-agent-on-step-finish-callback';
    12â†’import { ToolLoopAgentSettings } from './tool-loop-agent-settings';
    13â†’
    14â†’/**
    15â†’ * A tool loop agent is an agent that runs tools in a loop. In each step,
    16â†’ * it calls the LLM, and if there are tool calls, it executes the tools
    17â†’ * and calls the LLM again in a new step with the tool results.
    18â†’ *
    19â†’ * The loop continues until:
    20â†’ * - A finish reasoning other than tool-calls is returned, or
    21â†’ * - A tool that is invoked does not have an execute function, or
    22â†’ * - A tool call needs approval, or
    23â†’ * - A stop condition is met (default stop condition is stepCountIs(20))
    24â†’ */
    25â†’export class ToolLoopAgent<
    26â†’  CALL_OPTIONS = never,
    27â†’  TOOLS extends ToolSet = {},
    28â†’  OUTPUT extends Output = never,
    29â†’> implements Agent<CALL_OPTIONS, TOOLS, OUTPUT>
    30â†’{
    31â†’  readonly version = 'agent-v1';
    32â†’
    33â†’  private readonly settings: ToolLoopAgentSettings<CALL_OPTIONS, TOOLS, OUTPUT>;
    34â†’
    35â†’  constructor(settings: ToolLoopAgentSettings<CALL_OPTIONS, TOOLS, OUTPUT>) {
    36â†’    this.settings = settings;
    37â†’  }
    38â†’
    39â†’  /**
    40â†’   * The id of the agent.
    41â†’   */
    42â†’  get id(): string | undefined {
    43â†’    return this.settings.id;
    44â†’  }
    45â†’
    46â†’  /**
    47â†’   * The tools that the agent can use.
    48â†’   */
    49â†’  get tools(): TOOLS {
    50â†’    return this.settings.tools as TOOLS;
    51â†’  }
    52â†’
    53â†’  private async prepareCall(options: {
    54â†’    prompt?: string | Array<import('@ai-sdk/provider-utils').ModelMessage>;
    55â†’    messages?: Array<import('@ai-sdk/provider-utils').ModelMessage>;
    56â†’    options?: CALL_OPTIONS;
    57â†’  }): Promise<
    58â†’    Omit<
    59â†’      ToolLoopAgentSettings<CALL_OPTIONS, TOOLS, OUTPUT>,
    60â†’      'prepareCall' | 'instructions' | 'onStepFinish'
    61â†’    > &
    62â†’      Prompt
    63â†’  > {
    64â†’    const { onStepFinish: _settingsOnStepFinish, ...settingsWithoutCallback } =
    65â†’      this.settings;
    66â†’
    67â†’    const baseCallArgs = {
    68â†’      ...settingsWithoutCallback,
    69â†’      stopWhen: this.settings.stopWhen ?? stepCountIs(20),
    70â†’      ...options,
    71â†’    };
    72â†’
    73â†’    const preparedCallArgs =
    74â†’      (await this.settings.prepareCall?.(
    75â†’        baseCallArgs as Parameters<
    76â†’          NonNullable<
    77â†’            ToolLoopAgentSettings<CALL_OPTIONS, TOOLS, OUTPUT>['prepareCall']
    78â†’          >
    79â†’        >[0],
    80â†’      )) ?? baseCallArgs;
    81â†’
    82â†’    const { instructions, messages, prompt, ...callArgs } = preparedCallArgs;
    83â†’
    84â†’    return {
    85â†’      ...callArgs,
    86â†’
    87â†’      // restore prompt types
    88â†’      ...({ system: instructions, messages, prompt } as Prompt),
    89â†’    };
    90â†’  }
    91â†’
    92â†’  private mergeOnStepFinishCallbacks(
    93â†’    methodCallback: ToolLoopAgentOnStepFinishCallback<TOOLS> | undefined,
    94â†’  ): ToolLoopAgentOnStepFinishCallback<TOOLS> | undefined {
    95â†’    const constructorCallback = this.settings.onStepFinish;
    96â†’
    97â†’    if (methodCallback && constructorCallback) {
    98â†’      return async (stepResult: StepResult<TOOLS>) => {
    99â†’        await constructorCallback(stepResult);
   100â†’        await methodCallback(stepResult);
   101â†’      };
   102â†’    }
   103â†’
   104â†’    return methodCallback ?? constructorCallback;
   105â†’  }
   106â†’
   107â†’  /**
   108â†’   * Generates an output from the agent (non-streaming).
   109â†’   */
   110â†’  async generate({
   111â†’    abortSignal,
   112â†’    timeout,
   113â†’    onStepFinish,
   114â†’    ...options
   115â†’  }: AgentCallParameters<CALL_OPTIONS, TOOLS>): Promise<
   116â†’    GenerateTextResult<TOOLS, OUTPUT>
   117â†’  > {
   118â†’    return generateText({
   119â†’      ...(await this.prepareCall(options)),
   120â†’      abortSignal,
   121â†’      timeout,
   122â†’      onStepFinish: this.mergeOnStepFinishCallbacks(onStepFinish),
   123â†’    });
   124â†’  }
   125â†’
   126â†’  /**
   127â†’   * Streams an output from the agent (streaming).
   128â†’   */
   129â†’  async stream({
   130â†’    abortSignal,
   131â†’    timeout,
   132â†’    experimental_transform,
   133â†’    onStepFinish,
   134â†’    ...options
   135â†’  }: AgentStreamParameters<CALL_OPTIONS, TOOLS>): Promise<
   136â†’    StreamTextResult<TOOLS, OUTPUT>
   137â†’  > {
   138â†’    return streamText({
   139â†’      ...(await this.prepareCall(options)),
   140â†’      abortSignal,
   141â†’      timeout,
   142â†’      experimental_transform,
   143â†’      onStepFinish: this.mergeOnStepFinishCallbacks(onStepFinish),
   144â†’    });
   145â†’  }
   146â†’}
