    42â†’  uiMessages: unknown[];
    43â†’  abortSignal?: AbortSignal;
    44â†’  timeout?: TimeoutConfiguration;
    45â†’  options?: CALL_OPTIONS;
    46â†’  experimental_transform?:
    47â†’    | StreamTextTransform<TOOLS>
    48â†’    | Array<StreamTextTransform<TOOLS>>;
    49â†’  onStepFinish?: ToolLoopAgentOnStepFinishCallback<TOOLS>;
    50â†’} & UIMessageStreamResponseInit &
    51â†’  UIMessageStreamOptions<
    52â†’    UIMessage<MESSAGE_METADATA, never, InferUITools<TOOLS>>
    53â†’  >): Promise<Response> {
