     1â†’import { executeTool, ModelMessage } from '@ai-sdk/provider-utils';
     2â†’import { Tracer } from '@opentelemetry/api';
     3â†’import { assembleOperationName } from '../telemetry/assemble-operation-name';
     4â†’import { recordErrorOnSpan, recordSpan } from '../telemetry/record-span';
     5â†’import { selectTelemetryAttributes } from '../telemetry/select-telemetry-attributes';
     6â†’import { TelemetrySettings } from '../telemetry/telemetry-settings';
     7â†’import { TypedToolCall } from './tool-call';
     8â†’import { ToolOutput } from './tool-output';
     9â†’import { ToolSet } from './tool-set';
    10â†’import { TypedToolResult } from './tool-result';
    11â†’import { TypedToolError } from './tool-error';
    12â†’
    13â†’export async function executeToolCall<TOOLS extends ToolSet>({
    14â†’  toolCall,
    15â†’  tools,
    16â†’  tracer,
    17â†’  telemetry,
    18â†’  messages,
    19â†’  abortSignal,
    20â†’  experimental_context,
    21â†’  onPreliminaryToolResult,
    22â†’}: {
    23â†’  toolCall: TypedToolCall<TOOLS>;
    24â†’  tools: TOOLS | undefined;
    25â†’  tracer: Tracer;
    26â†’  telemetry: TelemetrySettings | undefined;
    27â†’  messages: ModelMessage[];
    28â†’  abortSignal: AbortSignal | undefined;
    29â†’  experimental_context: unknown;
    30â†’  onPreliminaryToolResult?: (result: TypedToolResult<TOOLS>) => void;
    31â†’}): Promise<ToolOutput<TOOLS> | undefined> {
    32â†’  const { toolName, toolCallId, input } = toolCall;
    33â†’  const tool = tools?.[toolName];
    34â†’
    35â†’  if (tool?.execute == null) {
    36â†’    return undefined;
    37â†’  }
    38â†’
    39â†’  return recordSpan({
    40â†’    name: 'ai.toolCall',
    41â†’    attributes: selectTelemetryAttributes({
    42â†’      telemetry,
    43â†’      attributes: {
    44â†’        ...assembleOperationName({
    45â†’          operationId: 'ai.toolCall',
    46â†’          telemetry,
    47â†’        }),
    48â†’        'ai.toolCall.name': toolName,
    49â†’        'ai.toolCall.id': toolCallId,
    50â†’        'ai.toolCall.args': {
    51â†’          output: () => JSON.stringify(input),
    52â†’        },
    53â†’      },
    54â†’    }),
    55â†’    tracer,
    56â†’    fn: async span => {
    57â†’      let output: unknown;
    58â†’
    59â†’      try {
    60â†’        const stream = executeTool({
    61â†’          execute: tool.execute!.bind(tool),
    62â†’          input,
    63â†’          options: {
    64â†’            toolCallId,
    65â†’            messages,
    66â†’            abortSignal,
    67â†’            experimental_context,
    68â†’          },
    69â†’        });
    70â†’
    71â†’        for await (const part of stream) {
    72â†’          if (part.type === 'preliminary') {
    73â†’            onPreliminaryToolResult?.({
    74â†’              ...toolCall,
    75â†’              type: 'tool-result',
    76â†’              output: part.output,
    77â†’              preliminary: true,
    78â†’            });
    79â†’          } else {
    80â†’            output = part.output;
    81â†’          }
    82â†’        }
    83â†’      } catch (error) {
    84â†’        recordErrorOnSpan(span, error);
    85â†’        return {
    86â†’          type: 'tool-error',
    87â†’          toolCallId,
    88â†’          toolName,
    89â†’          input,
    90â†’          error,
    91â†’          dynamic: tool.type === 'dynamic',
    92â†’          ...(toolCall.providerMetadata != null
    93â†’            ? { providerMetadata: toolCall.providerMetadata }
    94â†’            : {}),
    95â†’        } as TypedToolError<TOOLS>;
    96â†’      }
    97â†’
    98â†’      try {
    99â†’        span.setAttributes(
   100â†’          await selectTelemetryAttributes({
   101â†’            telemetry,
   102â†’            attributes: {
   103â†’              'ai.toolCall.result': {
   104â†’                output: () => JSON.stringify(output),
   105â†’              },
   106â†’            },
   107â†’          }),
   108â†’        );
   109â†’      } catch (ignored) {
   110â†’        // JSON stringify might fail if the result is not serializable,
   111â†’        // in which case we just ignore it. In the future we might want to
   112â†’        // add an optional serialize method to the tool interface and warn
   113â†’        // if the result is not serializable.
   114â†’      }
   115â†’
   116â†’      return {
   117â†’        type: 'tool-result',
   118â†’        toolCallId,
   119â†’        toolName,
   120â†’        input,
   121â†’        output,
   122â†’        dynamic: tool.type === 'dynamic',
   123â†’        ...(toolCall.providerMetadata != null
   124â†’          ? { providerMetadata: toolCall.providerMetadata }
   125â†’          : {}),
   126â†’      } as TypedToolResult<TOOLS>;
   127â†’    },
   128â†’  });
   129â†’}
