     4â†’export async function* executeTool<INPUT, OUTPUT>({
     5â†’  execute,
     6â†’  input,
     7â†’  options,
     8â†’}: {
     9â†’  execute: ToolExecuteFunction<INPUT, OUTPUT>;
    10â†’  input: INPUT;
    11â†’  options: ToolExecutionOptions;
    12â†’}): AsyncGenerator<
    13â†’  { type: 'preliminary'; output: OUTPUT } | { type: 'final'; output: OUTPUT }
    14â†’> {
    15â†’  const result = execute(input, options);
    16â†’
    17â†’  if (isAsyncIterable(result)) {
    18â†’    let lastOutput: OUTPUT | undefined;
    19â†’    for await (const output of result) {
    20â†’      lastOutput = output;
    21â†’      yield { type: 'preliminary', output };
    22â†’    }
    23â†’    yield { type: 'final', output: lastOutput! };
    24â†’  } else {
    25â†’    yield { type: 'final', output: await result };
    26â†’  }
    27â†’}
