   305â†’
   306â†’## Forced Tool Calling
   307â†’
   308â†’You can force the agent to always use tools by combining `toolChoice: 'required'` with a `done` tool that has no `execute` function. This pattern ensures the agent uses tools for every step and stops only when it explicitly signals completion.
   309â†’
   310â†’```ts
   311â†’import { ToolLoopAgent, tool } from 'ai';
   312â†’import { z } from 'zod';
   313â†’__PROVIDER_IMPORT__;
   314â†’
   315â†’const agent = new ToolLoopAgent({
   316â†’  model: __MODEL__,
   317â†’  tools: {
   318â†’    search: searchTool,
   319â†’    analyze: analyzeTool,
   320â†’    done: tool({
   321â†’      description: 'Signal that you have finished your work',
   322â†’      inputSchema: z.object({
   323â†’        answer: z.string().describe('The final answer'),
   324â†’      }),
   325â†’      // No execute function - stops the agent when called
   326â†’    }),
   327â†’  },
   328â†’  toolChoice: 'required', // Force tool calls at every step
   329â†’});
   330â†’
   331â†’const result = await agent.generate({
   332â†’  prompt: 'Research and analyze this topic, then provide your answer.',
   333â†’});
   334â†’
   335â†’// extract answer from done tool call
   336â†’const toolCall = result.staticToolCalls[0]; // tool call from final step
   337â†’if (toolCall?.toolName === 'done') {
   338â†’  console.log(toolCall.input.answer);
   339â†’}
